+fn mindmap_subtree_height(
+    idx: usize,
+    children: &[Vec<usize>],
+    node_sizes: &[(f64, f64)],
+    vertical_gap: f64,
+    memo: &mut [Option<f64>],
+    visiting: &mut [bool],
+) -> f64 {
+    if let Some(value) = memo[idx] {
+        return value;
+    }
+    if visiting[idx] {
+        return node_sizes[idx].1;
+    }
+    visiting[idx] = true;
+    let mut total = 0.0;
+    for &child in &children[idx] {
+        total += mindmap_subtree_height(child, children, node_sizes, vertical_gap, memo, visiting)
+            + vertical_gap;
+    }
+    if !children[idx].is_empty() {
+        total -= vertical_gap;
+    }
+    let height = node_sizes[idx].1.max(total);
+    memo[idx] = Some(height);
+    visiting[idx] = false;
+    height
+}
