+#[allow(dead_code, clippy::too_many_arguments)]
+fn mindmap_layout_side_children(
+    entries: &[(usize, f64)],
+    side_dir: f64,
+    parent_idx: usize,
+    parent_center: LayoutPoint,
+    depth: usize,
+    children: &[Vec<usize>],
+    node_sizes: &[(f64, f64)],
+    vertical_gap: f64,
+    level_gap: f64,
+    centers: &mut [LayoutPoint],
+    depths: &mut [usize],
