+    let child_ids = &children[parent_idx];
+    if child_ids.is_empty() {
+        return;
+    }
+    let mut child_entries: Vec<(usize, f64)> = child_ids
+        .iter()
+        .map(|&child| {
+            let height =
+                mindmap_subtree_height(child, children, node_sizes, vertical_gap, memo, visiting);
